      $b.coverage_ledger.accepted_visual_tasks[0].covered_beat_ids=@('BEAT-R6-001','BEAT-R6-003');$b.coverage_ledger.visual_insert_occurrences[0].covered_beat_ids=@('BEAT-R6-001','BEAT-R6-003')
    }
  }
