  $brief=[ordered]@{brief_id=[string]$b.structure_plan.brief_id;content_goal='Validate a deterministic delivery candidate';core_promise=[string]$b.structure_plan.core_promise;brief_status='ready'}
  $package=[ordered]@{schema_id='taoge://schemas/r7/platform-package/v0.1';schema_version='0.1';platform_package_id="PK-$SessionId";draft_ref=[ordered]@{artifact_id=[string]$b.draft.draft_id};primary_platform='douyin';packages=@([ordered]@{platform='douyin';title='Sample video';cover_title='Sample cover';body_text='Sample delivery body';hashtags=@('#sample');notes=@()},[ordered]@{platform='xiaohongshu';title='Sample note';cover_title='Sample note cover';body_text='Sample note body';hashtags=@('#sample');notes=@()},[ordered]@{platform='wechat_channels';title='Sample channel';cover_title='Sample channel cover';body_text='Sample channel body';hashtags=@('#sample');notes=@()});package_status='package_pass_with_warnings';next_skill='platform-cover-composer'}
  $assetPath='assets/visuals/sample.png';Write-R7H4TinyPng (Join-Path $session $assetPath);$sidecar='assets/visuals/sample.record.json';Write-P0EvidenceAtomicText (Join-Path $session $sidecar) (ConvertTo-P0EvidenceJsonText ([ordered]@{record_id="REC-$SessionId";provider_invoked=$true}));$assetDigest=Get-R7RuntimeHash (Join-Path $session $assetPath)
  $assetSet=[ordered]@{schema_id='taoge://schemas/r7/image-asset-set/v0.1';schema_version='0.1';image_asset_set_id="ASSETSET-$SessionId";coverage_ledger_ref=[ordered]@{artifact_id=[string]$b.coverage_ledger.visual_coverage_ledger_id};assets=@([ordered]@{asset_id='ASSET-R6-001';visual_task_id='VTASK-R6-001';relative_path=$assetPath;sha256=$assetDigest;media_type='image/png';role='visual_insert';source_mode='provider_generated';provider_invoked=$true;width_px=1600;height_px=900;alt_text='Sample explanatory visual';visual_text_summary='A sample visual relation';sidecar_path=$sidecar;generation_record_path=$sidecar});provider_invocation_count=1;asset_set_status='ready_with_warnings';next_skill='script-visual-alignment-review'}
